export default function SkillIcon({ type }: SkillIconProps) {
    switch (type) {
        case 'git':
            return <GitIcon />;

        case 'mongodb':
            return <MongoDBIcon />;

        case 'mysql':
            return <MySQLIcon />;

        case 'graphql':
            return <GraphQLIcon />;

        case 'docker':
            return <DockerIcon />;

        case 'aws':
            return <AWSIcon />;

        case 'azure':
            return <AzureIcon />;

        case 'oracle':
            return <OracleIcon />;

        default:
            return null;
    }
}